#include <bits/stdc++.h>
using namespace std;
const int N=102,M=1e5+5;
int n,m,a[N],c[N];
int main(){
    while(scanf("%d%d",&n,&m),n){
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        for(int i=1;i<=n;i++)
            scanf("%d",&c[i]);
        bitset<M> f("1");
        for(int i=1;i<=n;i++){
            int k=1;
            for(;k<=c[i] && k*a[i]<=m;c[i]-=k,k*=2)
                f|=f<<(k*a[i]);
            if(c[i] && c[i]*a[i]<=m)
                f|=f<<(c[i]*a[i]);
        }
        int sum=0;
        for(int i=1;i<=m;i++)
            sum+=f[i];
        printf("%d\n",sum);
    }
    return 0;
}
